import json

# Read the most recent ThingSpeak cron session - it ran Apr 30 at 03:05
with open('/home/ocarjohann/.hermes/sessions/session_cron_0a5472458bd9_20260430_030050.json') as f:
    data = json.load(f)

# Find the user message (which contains the cron result/prompt)
for m in data.get('messages', []):
    role = m.get('role', '')
    content = m.get('content', '')
    if isinstance(content, str):
        print(f"=== [{role}] ===")
        print(content[:2000])
        print()
    elif isinstance(content, list):
        for item in content:
